import{_ as t,o as i,c as o,ag as s}from"./chunks/framework.NIzFHKo_.js";const h=JSON.parse('{"title":"QiAccess Start Operating Blueprint","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/60_knowledge/90_superseded_sources/qi_os_home_blueprint.md","filePath":"10_core/60_knowledge/90_superseded_sources/qi_os_home_blueprint.md"}'),r={name:"10_core/60_knowledge/90_superseded_sources/qi_os_home_blueprint.md"};function l(a,e,n,d,c,u){return i(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="qiaccess-start-operating-blueprint" tabindex="-1">QiAccess Start Operating Blueprint <a class="header-anchor" href="#qiaccess-start-operating-blueprint" aria-label="Permalink to &quot;QiAccess Start Operating Blueprint&quot;">​</a></h1><p><strong>Status:</strong> Active doctrine <strong>Primary runtime:</strong> qiserver <strong>Knowledge base:</strong> Wiki.js plus repo docs <strong>Storage backbone:</strong> Google Drive / QiNexus</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>QiAccess Start is Cody&#39;s cognitive front door.</p><p>It exists to:</p><ol><li>reduce cognitive load</li><li>capture what matters before it disappears</li><li>open the right tool fast</li><li>store knowledge in the right place</li><li>retrieve context when needed</li><li>surface patterns and insights</li><li>build toward AI-assisted wisdom</li></ol><h2 id="root-model" tabindex="-1">Root Model <a class="header-anchor" href="#root-model" aria-label="Permalink to &quot;Root Model&quot;">​</a></h2><p>QiAccess Start has seven top-level roots only:</p><ol><li><code>Home</code></li><li><code>Start</code></li><li><code>Capture</code></li><li><code>Knowledge</code></li><li><code>Memory</code></li><li><code>Insights</code></li><li><code>System</code></li></ol><h3 id="root-intent" tabindex="-1">Root intent <a class="header-anchor" href="#root-intent" aria-label="Permalink to &quot;Root intent&quot;">​</a></h3><ul><li><code>Home</code>: orient the day and expose the shortest useful paths</li><li><code>Start</code>: launch tools, services, projects, and working surfaces</li><li><code>Capture</code>: intake notes, links, reminders, files, and observations fast</li><li><code>Knowledge</code>: point to docs, manuals, runbooks, and reference sources</li><li><code>Memory</code>: preserve timeline, decisions, and continuity once ingestion exists</li><li><code>Insights</code>: hold derived summaries, pattern detection, and future analysis layers</li><li><code>System</code>: expose nested admin, private infrastructure, governance, and diagnostics</li></ul><h2 id="system-subroutes" tabindex="-1">System Subroutes <a class="header-anchor" href="#system-subroutes" aria-label="Permalink to &quot;System Subroutes&quot;">​</a></h2><p>System owns:</p><ul><li><code>/system/access</code></li><li><code>/system/server</code></li><li><code>/system/storage</code></li><li><code>/system/integrations</code></li><li><code>/system/settings</code></li><li><code>/system/blueprint</code></li><li><code>/system/roadmap</code></li><li><code>/system/security</code></li><li><code>/system/diagnostics</code></li></ul><p>These do not become top-level roots.</p><h2 id="current-build-rule" tabindex="-1">Current Build Rule <a class="header-anchor" href="#current-build-rule" aria-label="Permalink to &quot;Current Build Rule&quot;">​</a></h2><p>Prototype inside the existing repo and preserve what already works.</p><ul><li>no repo split</li><li>no auth rebuild</li><li>no deployment churn before flow is validated</li><li>no fake intelligence claims</li><li>static or honest placeholder content is acceptable during stabilization</li></ul><h2 id="retained-constitutional-rules" tabindex="-1">Retained Constitutional Rules <a class="header-anchor" href="#retained-constitutional-rules" aria-label="Permalink to &quot;Retained Constitutional Rules&quot;">​</a></h2><p>The following legacy QiOS rules remain active because they still serve QiAccess Start:</p><ol><li>one canonical identity per object</li><li>one clear home per concern</li><li>metadata precedes automation</li><li>lineage survives transformation</li><li>derived systems are not truth sources</li><li>exposure boundaries must be explicit</li><li>structural changes earn ADR review</li></ol><h2 id="legacy-disposition" tabindex="-1">Legacy Disposition <a class="header-anchor" href="#legacy-disposition" aria-label="Permalink to &quot;Legacy Disposition&quot;">​</a></h2><p>The older business, tenant, and client-platform blueprint is quarantined.</p><p>Keep the useful governance DNA. Do not let the retired model override the seven-root cognitive front door.</p>',24)])])}const m=t(r,[["render",l]]);export{h as __pageData,m as default};
